1	//! Report data type and rendering (matches the oracle's WARNING comment).
2	
3	use std::collections::BTreeSet;
4	
5	/// One topic block of the wellformedness report: a header `topic` and the
6	/// already-formatted `message` body that appears beneath its underline.
7	#[derive(Debug, Clone, PartialEq)]
8	pub struct WfError {
9	    pub topic: String,
10	    pub message: String,
11	}
12	
13	impl WfError {
14	    pub fn new(topic: impl Into<String>, message: impl Into<String>) -> Self {
15	        WfError {
16	            topic: topic.into(),
17	            message: message.into(),
18	        }
19	    }
20	}
21	
22	pub type WfReport = Vec<WfError>;
23	
24	/// The success line the oracle prints when no check fails.
25	pub const SUCCESS_LINE: &str = "/* All wellformedness checks were successful. */";
26	
27	/// A topic header formatted exactly as the oracle renders it: the title on one
28	/// line, then `=` repeated to the title's (character) length on the next.
29	pub fn underline_topic(title: &str) -> String {
30	    let n = title.chars().count();
31	    let bar: String = std::iter::repeat('=').take(n).collect();
32	    format!("{}\n{}", title, bar)
33	}
34	
35	/// The set of distinct topics present in a report.
36	pub fn topics(report: &WfReport) -> BTreeSet<String> {
37	    report.iter().map(|e| e.topic.clone()).collect()
38	}
39	
40	/// Render one topic block: header + underline + blank line + body.
41	fn render_block(e: &WfError) -> String {
42	    format!("{}\n\n{}", underline_topic(&e.topic), e.message)
43	}
44	
45	/// Render a full report as the oracle's WARNING comment (byte-identical), or
46	/// the success line for an empty report.
47	pub fn render_report(report: &WfReport) -> String {
48	    if report.is_empty() {
49	        return SUCCESS_LINE.to_string();
50	    }
51	    let blocks: Vec<String> = report.iter().map(render_block).collect();
52	    let inner = format!(
53	        "WARNING: the following wellformedness checks failed!\n\n{}",
54	        blocks.join("\n\n")
55	    );
56	    format!("/*\n{}\n*/", inner)
57	}
58	
59	/// Insert `errors` into `report` immediately before the first entry whose topic
60	/// is one of `anchors`. If no anchor is present, append at the end.
61	pub fn insert_wf_before(report: &mut Vec<WfError>, errors: Vec<WfError>, anchors: &[&str]) {
62	    if errors.is_empty() {
63	        return;
64	    }
65	    match report
66	        .iter()
67	        .position(|e| anchors.iter().any(|a| *a == e.topic))
68	    {
69	        Some(i) => {
70	            let tail = report.split_off(i);
71	            report.extend(errors);
72	            report.extend(tail);
73	        }
74	        None => report.extend(errors),
75	    }
76	}
