1	//! Term / fact pretty-printer reproducing the oracle's rendering.
2	//!
3	//! Every rule here traces to an oracle observation (see workspace/BEHAVIOR.md
4	//! and the probes t_terms, t_xor, t_nat, f_nullary).
5	
6	use crate::ast::*;
7	
8	/// Render a variable: sort prefix + base name + optional ".idx" (idx > 0).
9	pub fn pp_var(v: &VarSpec) -> String {
10	    let prefix = match v.sort {
11	        SortHint::Fresh => "~",
12	        SortHint::Pub => "$",
13	        SortHint::Nat => "%",
14	        SortHint::Node => "#",
15	        SortHint::Msg | SortHint::Untagged => "",
16	        // Suffix-sorted variables carry an explicit ":sort"; best-effort.
17	        SortHint::Suffix(_) => "",
18	    };
19	    if v.idx > 0 {
20	        format!("{}{}.{}", prefix, v.name, v.idx)
21	    } else {
22	        format!("{}{}", prefix, v.name)
23	    }
24	}
25	
26	/// Flatten a right-nested pair term into its element list.
27	fn flatten_pair(t: &Term, out: &mut Vec<String>) {
28	    match t {
29	        Term::Pair(items) => {
30	            for it in items {
31	                flatten_pair(it, out);
32	            }
33	        }
34	        Term::App(name, args) if name == "pair" && args.len() == 2 => {
35	            flatten_pair(&args[0], out);
36	            flatten_pair(&args[1], out);
37	        }
38	        other => out.push(pp_term(other)),
39	    }
40	}
41	
42	/// Collect the operands of a left/right-nested chain of the same binary op.
43	fn flatten_binop(op: BinOp, t: &Term, out: &mut Vec<Term>) {
44	    if let Term::BinOp(o, a, b) = t {
45	        if *o == op {
46	            flatten_binop(op, a, out);
47	            flatten_binop(op, b, out);
48	            return;
49	        }
50	    }
51	    out.push(t.clone());
52	}
53	
54	fn pp_binop(op: BinOp, a: &Term, b: &Term) -> String {
55	    match op {
56	        // Exponentiation is shown infix without surrounding parentheses.
57	        BinOp::Exp => format!("{}^{}", pp_term(a), pp_term(b)),
58	        // The AC operators are parenthesised and joined by their symbol.
59	        BinOp::Mult | BinOp::Union | BinOp::Xor | BinOp::NatPlus => {
60	            let sym = match op {
61	                BinOp::Mult => "*",
62	                BinOp::Union => "++",
63	                BinOp::Xor => "\u{2295}", // (+)
64	                BinOp::NatPlus => "%+",
65	                BinOp::Exp => unreachable!(),
66	            };
67	            let whole = Term::BinOp(op, Box::new(a.clone()), Box::new(b.clone()));
68	            let mut operands = Vec::new();
69	            flatten_binop(op, &whole, &mut operands);
70	            let mut parts: Vec<String> = operands.iter().map(pp_term).collect();
71	            // XOR arguments are normalised (sorted); observed in probe t_xor.
72	            if op == BinOp::Xor {
73	                parts.sort();
74	            }
75	            format!("({})", parts.join(sym))
76	        }
77	    }
78	}
79	
80	/// Render a term the way the oracle prints it inside facts.
81	pub fn pp_term(t: &Term) -> String {
82	    match t {
83	        Term::Var(v) => pp_var(v),
84	        Term::PubLit(s) => format!("'{}'", s),
85	        Term::FreshLit(s) => format!("~'{}'", s),
86	        Term::NatLit(s) => format!("%'{}'", s),
87	        Term::Number(n) => n.to_string(),
88	        Term::NumberOne => "1".to_string(),
89	        Term::NatOne => "%1".to_string(),
90	        Term::DhNeutral => "DH_neutral".to_string(),
91	        Term::App(name, args) => {
92	            if name == "pair" && args.len() == 2 {
93	                let mut elems = Vec::new();
94	                flatten_pair(t, &mut elems);
95	                format!("<{}>", elems.join(", "))
96	            } else if args.is_empty() {
97	                name.clone()
98	            } else {
99	                let parts: Vec<String> = args.iter().map(pp_term).collect();
100	                format!("{}({})", name, parts.join(", "))
101	            }
102	        }
103	        Term::AlgApp(name, a, b) => format!("{}({}, {})", name, pp_term(a), pp_term(b)),
104	        Term::Pair(_) => {
105	            let mut elems = Vec::new();
106	            flatten_pair(t, &mut elems);
107	            format!("<{}>", elems.join(", "))
108	        }
109	        Term::Diff(a, b) => format!("diff({}, {})", pp_term(a), pp_term(b)),
110	        Term::BinOp(op, a, b) => pp_binop(*op, a, b),
111	        Term::PatMatch(inner) => format!("={}", pp_term(inner)),
112	    }
113	}
114	
115	/// Render a fact: optional `!` for persistent, then `Name( args )`.
116	/// Empty argument list renders as `Name( )`.
117	pub fn pp_fact(f: &Fact) -> String {
118	    let bang = if f.persistent { "!" } else { "" };
119	    if f.args.is_empty() {
120	        format!("{}{}( )", bang, f.name)
121	    } else {
122	        let parts: Vec<String> = f.args.iter().map(pp_term).collect();
123	        format!("{}{}( {} )", bang, f.name, parts.join(", "))
124	    }
125	}
126	
127	/// Render a bracketed fact list as it appears inside a rule: `[ f1, f2 ]`, or
128	/// `[ ]` when empty.
129	pub fn pp_fact_list(fs: &[Fact]) -> String {
130	    if fs.is_empty() {
131	        "[ ]".to_string()
132	    } else {
133	        let parts: Vec<String> = fs.iter().map(pp_fact).collect();
134	        format!("[ {} ]", parts.join(", "))
135	    }
136	}
137	
138	// ---------------------------------------------------------------------------
139	// Equation layout (Subterm Convergence Warning entries)
140	// ---------------------------------------------------------------------------
141	// Calibrated against the oracle (probes t5_wl*/t5_tup*/t5_last* and the
142	// ble/mesh reference blocks). An equation renders flat as `    lhs = rhs`
143	// while it fits; otherwise the LHS keeps the 4-column indent and the RHS
144	// continues on the next line as `  = rhs`. Inside the RHS, function
145	// applications fill their comma-glued arguments at the column after the
146	// opening paren, tuples fill their `", "`-suffixed elements one column after
147	// the `<` (a line then ends with the trailing `", "`), and every fit check
148	// compares against min(100, 67 + nest of the current line) - the nest being
149	// the continuation column that started the line. A tuple element following a
150	// multi-line element always starts a fresh line, and the closing `>` drops to
151	// the tuple's start column when the last element was multi-line (or when it
152	// does not fit); an application's `)` always glues.
153	
154	fn eq_margin(line_nest: usize) -> usize {
155	    std::cmp::min(100, line_nest + 67)
156	}
157	
158	struct EqLayout {
159	    out: String,
160	    col: usize,
161	    line_nest: usize,
162	}
163	
164	impl EqLayout {
165	    fn emit(&mut self, s: &str) {
166	        self.out.push_str(s);
167	        self.col += s.chars().count();
168	    }
169	    fn newline(&mut self, nest: usize) {
170	        self.out.push('\n');
171	        self.out.push_str(&" ".repeat(nest));
172	        self.col = nest;
173	        self.line_nest = nest;
174	    }
175	    fn margin(&self) -> usize {
176	        eq_margin(self.line_nest)
177	    }
178	}
179	
180	/// The flattened element list of a tuple term, or `None` when `t` is not a
181	/// tuple (mirrors the flat printer's pair flattening).
182	fn tuple_elems(t: &Term) -> Option<Vec<Term>> {
183	    match t {
184	        Term::Pair(_) => (),
185	        Term::App(name, args) if name == "pair" && args.len() == 2 => (),
186	        _ => return None,
187	    }
188	    let mut parts = Vec::new();
189	    fn walk(t: &Term, out: &mut Vec<Term>) {
190	        match t {
191	            Term::Pair(items) => {
192	                for it in items {
193	                    walk(it, out);
194	                }
195	            }
196	            Term::App(name, args) if name == "pair" && args.len() == 2 => {
197	                walk(&args[0], out);
198	                walk(&args[1], out);
199	            }
200	            other => out.push(other.clone()),
201	        }
202	    }
203	    walk(t, &mut parts);
204	    Some(parts)
205	}
206	
207	/// Lay a term at the current position, breaking when it exceeds the margin.
208	/// Returns whether the layout spanned multiple lines.
209	fn lay_eq_term(t: &Term, st: &mut EqLayout) -> bool {
210	    let flat = pp_term(t);
211	    if st.col + flat.chars().count() <= st.margin() {
212	        st.emit(&flat);
213	        return false;
214	    }
215	    if let Some(elems) = tuple_elems(t) {
216	        let start_col = st.col;
217	        st.emit("<");
218	        let cont = st.col;
219	        let mut prev_multiline = false;
220	        for (i, e) in elems.iter().enumerate() {
221	            let sep = if i + 1 < elems.len() { ", " } else { "" };
222	            let flat_e = pp_term(e);
223	            let w = flat_e.chars().count() + sep.chars().count();
224	            if !prev_multiline && st.col + w <= st.margin() {
225	                st.emit(&flat_e);
226	                st.emit(sep);
227	            } else {
228	                st.newline(cont);
229	                prev_multiline = lay_eq_term(e, st);
230	                st.emit(sep);
231	            }
232	        }
233	        if prev_multiline || st.col + 1 > st.margin() {
234	            st.newline(start_col);
235	        }
236	        st.emit(">");
237	        return true;
238	    }
239	    match t {
240	        Term::App(name, args) if !args.is_empty() => {
241	            st.emit(name);
242	            st.emit("(");
243	            let cont = st.col;
244	            let mut first_on_line = true;
245	            for (i, a) in args.iter().enumerate() {
246	                let sep = if i + 1 < args.len() { "," } else { "" };
247	                let flat_a = pp_term(a);
248	                let lead = if first_on_line { 0 } else { 1 };
249	                let w = lead + flat_a.chars().count() + sep.chars().count();
250	                if st.col + w <= st.margin() {
251	                    if !first_on_line {
252	                        st.emit(" ");
253	                    }
254	                    st.emit(&flat_a);
255	                    st.emit(sep);
256	                    first_on_line = false;
257	                } else {
258	                    st.newline(cont);
259	                    lay_eq_term(a, st);
260	                    st.emit(sep);
261	                    first_on_line = false;
262	                }
263	            }
264	            st.emit(")");
265	        }
266	        // No other break points: emit flat (over-wide atoms overflow).
267	        _ => st.emit(&flat),
268	    }
269	    true
270	}
271	
272	/// Render one flagged equation for the Subterm Convergence Warning block:
273	/// `    lhs = rhs` on one line while it fits within column 71, else the
274	/// wrapped form with `  = ` starting the RHS.
275	pub fn pp_equation(lhs: &Term, rhs: &Term) -> String {
276	    let flat = format!("    {} = {}", pp_term(lhs), pp_term(rhs));
277	    if flat.chars().count() <= eq_margin(4) {
278	        return flat;
279	    }
280	    let mut st = EqLayout {
281	        out: format!("    {}\n  = ", pp_term(lhs)),
282	        col: 4,
283	        line_nest: 2,
284	    };
285	    lay_eq_term(rhs, &mut st);
286	    st.out
287	}
288	
289	/// Render a rule the way the oracle prints it (single-line body; the oracle
290	/// wraps very long rules across several lines - see BEHAVIOR.md gaps):
291	///
292	/// ```text
293	/// rule (modulo E) Name:
294	///    [ prems ] --> [ concls ]
295	/// ```
296	///
297	/// with `--[ acts ]->` in place of `-->` when the rule has action facts.
298	pub fn pp_rule(r: &Rule) -> String {
299	    let modulo = r.modulo.as_deref().unwrap_or("E");
300	    let prems = pp_fact_list(&r.premises);
301	    let concls = pp_fact_list(&r.conclusions);
302	    let arrow = if r.actions.is_empty() {
303	        "-->".to_string()
304	    } else {
305	        let acts: Vec<String> = r.actions.iter().map(pp_fact).collect();
306	        format!("--[ {} ]->", acts.join(", "))
307	    };
308	    format!("rule (modulo {}) {}:\n   {} {} {}", modulo, r.name, prems, arrow, concls)
309	}
