759	pub fn fact_multiplicity(thy: &Theory) -> Vec<WfError> {
760	    let uses = gather_fact_uses(thy);
761	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
762	    for (name, us) in &uses {
763	        let mults: std::collections::BTreeSet<bool> = us.iter().map(|u| u.persistent).collect();
764	        if mults.len() < 2 {
765	            continue;
766	        }
767	        let mut seen: Vec<(&str, String, bool, String)> = Vec::new();
768	        let mut items: Vec<String> = Vec::new();
769	        for u in us {
770	            let k = (u.label, u.owner.clone(), u.persistent, u.render.clone());
771	            if seen.contains(&k) {
772	                continue;
773	            }
774	            seen.push(k);
775	            let n = items.len() + 1;
776	            let m = if u.persistent { "Persistent" } else { "Linear" };
777	            items.push(format!(
778	                "    {}. {} `{}', multiplicity (persistence) {}\n         {}",
779	                n, u.label, u.owner, m, u.render
780	            ));
781	        }
782	        conflicts.push((name.to_lowercase(), items));
783	    }
784	    if conflicts.is_empty() {
785	        return vec![];
786	    }
787	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
788	    let msg = render_fact_blocks(
789	        &conflicts,
790	        "Same fact is used with different multiplicities, i.e., !Fact() (Persistent fact) exists along with Fact() (Linear) in your rules. ",
791	        "Check the multiplicity (persistence) of your facts.",
792	    );
793	    vec![WfError::new(T_MULT, msg)]
794	}
