885	/// Nearest RHS fact by name edit distance, if within threshold (<= 3).
886	fn nearest_rhs<'a>(name: &str, rhs: &'a [FactId]) -> Option<&'a FactId> {
887	    let mut best: Option<(usize, &FactId)> = None;
888	    for f in rhs {
889	        let d = edit_distance(name, &f.name);
890	        match best {
891	            Some((bd, _)) if d >= bd => {}
892	            _ => best = Some((d, f)),
893	        }
894	    }
895	    match best {
896	        Some((d, f)) if d <= 3 => Some(f),
897	        _ => None,
898	    }
899	}
