901	fn edit_distance(a: &str, b: &str) -> usize {
902	    let a: Vec<char> = a.chars().collect();
903	    let b: Vec<char> = b.chars().collect();
904	    let mut prev: Vec<usize> = (0..=b.len()).collect();
905	    let mut cur = vec![0usize; b.len() + 1];
906	    for i in 1..=a.len() {
907	        cur[0] = i;
908	        for j in 1..=b.len() {
909	            let cost = if a[i - 1] == b[j - 1] { 0 } else { 1 };
910	            cur[j] = (prev[j] + 1).min(cur[j - 1] + 1).min(prev[j - 1] + cost);
911	        }
912	        std::mem::swap(&mut prev, &mut cur);
913	    }
914	    prev[b.len()]
915	}
