    // two). No RHS facts exist, so no "Perhaps you want to use" suggestions
    // fire. Mirrors the ble target and probes lhs1/lhs2.
    let arity4 = || vec![mv("a"), mv("b"), mv("c"), mv("d")];
    let arity2 = || vec![mv("a"), mv("b")];
