]
.iter()
.enumerate()
.map(|(i, (rl, nm))| format!("  {}.{}", i + 1, &entry(rl, nm)[1..]))
.collect::<Vec<_>>()
.join("\n  \n");
assert_eq!(r[0].message, want);

